#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int rooms[n], heaters[m];
        for (int i = 0; i < n; i++) scanf("%d", &rooms[i]);
        for (int i = 0; i < m; i++) scanf("%d", &heaters[i]);
        qsort(rooms, n, sizeof(int), compare);
        qsort(heaters, m, sizeof(int), compare);
        int i = 0, j = 0, count = 0;
        while (i < n) {
            while (j < m && heaters[j] < rooms[i]) j++;
            if (j == m) break;
            count++;
            i++;
            j++;
        }
        printf("%d\n", count);
    }
    return 0;
}

