import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[] rooms = new int[n];
            int[] heaters = new int[m];
            for (int i = 0; i < n; i++) rooms[i] = scanner.nextInt();
            for (int i = 0; i < m; i++) heaters[i] = scanner.nextInt();
            Arrays.sort(rooms);
            Arrays.sort(heaters);
            int i = 0, j = 0, count = 0;
            while (i < n) {
                while (j < m && heaters[j] < rooms[i]) j++;
                if (j == m) break;
                count++;
                i++;
                j++;
            }
            System.out.println(count);
        }
    }
}

